    '<script>',
    'function getAuthHeader() { const token = localStorage.getItem("token"); return token ? { "Authorization": "Bearer " + token } : {}; }',
    'function showMessage(msg, type) { const div = document.getElementById("messageArea"); div.innerHTML = `<div class="message ${type}">${msg}</div>`; setTimeout(() => div.innerHTML = "", 5000); }',
    'async function apiFetch(endpoint, options = {}) { const headers = { "Content-Type": "application/json", ...getAuthHeader(), ...options.headers }; const res = await fetch("/api" + endpoint, { ...options, headers }); if (!res.ok) { let err = `Errore ${res.status}`; try { const data = await res.json(); err = data.message || err; } catch(e) {} throw new Error(err); } return res.json(); }',
    'function restoreSession() { return !!localStorage.getItem("token"); }',
    'function logout() { localStorage.removeItem("token"); localStorage.removeItem("user"); window.location.href = "Login.html"; }',
    'let magazzini = [], settori = [], categorie = [], marche = []; let articoliCorrente = []; let sortColumn = "codice", sortAsc = true; let currentObsId = null, currentVenditaId = null, currentVenditaTipo = null, currentVenditaSigle = []; let currentSigleArticoloId = null;',
