    'async function caricaSoggettiPerTipoVendita(tipo) { const selectSoggetto = document.getElementById("venditaSoggettoId"); if (!selectSoggetto) return; if (!tipo) { selectSoggetto.innerHTML = "<option value=\"\">Seleziona prima il tipo</option>"; selectSoggetto.disabled = true; return; } selectSoggetto.innerHTML = "<option value=\"\">Caricamento...</option>"; selectSoggetto.disabled = true; try { const data = await apiFetch(`/soggetti/tipo/${tipo}`); selectSoggetto.innerHTML = "<option value=\"\">Seleziona soggetto...</option>"; if (Array.isArray(data) && data.length) { data.forEach(item => { let testo = tipo === "PROMOTER" ? `${item.nome} ${item.cognome || ""}`.trim() : item.nome; selectSoggetto.appendChild(new Option(testo, item.id)); }); } else { selectSoggetto.innerHTML = "<option value=\"\">Nessun soggetto trovato</option>"; } selectSoggetto.disabled = false; } catch (err) { selectSoggetto.innerHTML = "<option value=\"\">Errore nel caricamento</option>"; selectSoggetto.disabled = true; } }',
    'async function apriModaleVendita(id, descrizione, tipoOggetto, disponibile) { currentVenditaId = id; currentVenditaTipo = tipoOggetto; document.getElementById("venditaOggettoDesc").innerText = descrizione; document.getElementById("venditaDisponibile").innerText = disponibile; const qtyInput = document.getElementById("venditaQuantita"); qtyInput.max = disponibile; qtyInput.value = disponibile > 0 ? 1 : 0; document.getElementById("venditaImporto").value = ""; document.getElementById("venditaNote").value = ""; const tipoSelect = document.getElementById("venditaTipoSoggetto"); const soggettoSelect = document.getElementById("venditaSoggettoId"); tipoSelect.value = ""; soggettoSelect.innerHTML = "<option value=\"\">Seleziona prima il tipo</option>"; soggettoSelect.disabled = true; const siglaGroup = document.getElementById("venditaSiglaGroup"); const siglaSelect = document.getElementById("venditaSiglaId"); if (tipoOggetto === "ARTICOLO") { try { const sigle = await apiFetch(`/articoli/${id}/sigle`); currentVenditaSigle = sigle.filter(s => s.quantita > 0); siglaSelect.innerHTML = "<option value=\"\">Qualsiasi sigla</option>"; for (const s of currentVenditaSigle) { const option = document.createElement("option"); option.value = s.id; option.textContent = `${s.sigla} (disponibile: ${s.quantita})`; siglaSelect.appendChild(option); } siglaGroup.style.display = "block"; } catch (err) { console.error(err); siglaGroup.style.display = "none"; } } else { siglaGroup.style.display = "none"; } document.getElementById("modalVendita").style.display = "flex"; }',
    'function chiudiModalVendita() { document.getElementById("modalVendita").style.display = "none"; currentVenditaId = null; currentVenditaSigle = []; }',
    'async function confermaVendita() { const clienteId = document.getElementById("venditaSoggettoId").value; const quantita = parseInt(document.getElementById("venditaQuantita").value); const importo = document.getElementById("venditaImporto").value; const note = document.getElementById("venditaNote").value.trim(); const siglaId = document.getElementById("venditaSiglaId").value; if (!clienteId) { showMessage("Seleziona un soggetto", "error"); return; } if (isNaN(quantita) || quantita <= 0) { showMessage("Quantità non valida", "error"); return; } if (currentVenditaTipo === "ARTICOLO" && siglaId) { const sigla = currentVenditaSigle.find(s => s.id == siglaId); if (!sigla || sigla.quantita < quantita) { showMessage(`La sigla selezionata ha solo ${sigla ? sigla.quantita : 0} pezzi disponibili`, "error"); return; } } const oggetti = [{ tipoOggetto: currentVenditaTipo, oggettoId: currentVenditaId, quantita, siglaId: siglaId || null }]; try { const res = await apiFetch("/vendite", { method: "POST", body: JSON.stringify({ oggetti, clienteId, importo: importo || null, note }) }); if (res.success) { showMessage(res.message, "success"); chiudiModalVendita(); refreshTabella(); } else { showMessage(res.message, "error"); } } catch (err) { showMessage(err.message, "error"); } }',
    'function apriNuovoSoggetto() { window.open("GestioneSoggetti.html", "_blank"); }',
    'async function caricaAnagrafiche() { try { [magazzini, settori, categorie, marche] = await Promise.all([ apiFetch("/anagrafiche/magazzini"), apiFetch("/anagrafiche/settori"), apiFetch("/anagrafiche/categorie"), apiFetch("/anagrafiche/marche") ]); function popola(sel, items, valKey, textKey) { sel.innerHTML = "<option value=\"\">Seleziona</option>"; items.forEach(i => sel.appendChild(new Option(i[textKey], i[valKey]))); } popola(magazzinoSelect, magazzini, "id", "nome"); popola(settoreSelect, settori, "id", "nome"); popola(categoriaSelect, categorie, "id", "nome"); popola(marcaSelect, marche, "id", "nome"); } catch(err) { showMessage("Errore caricamento anagrafiche", "error"); } }',
    'const filterFields = ["magazzino","settore","categoria","marca","descrizione","lunghezza","durezza","codice_modello"]; const endpointMap = { descrizione: "/articoli/valori/descrizioni", lunghezza: "/articoli/valori/lunghezze", durezza: "/articoli/valori/durezze", codice_modello: "/articoli/valori/modelli" };',
    'function getCurrentFilters() { const f = {}; for (let field of filterFields) { let el = document.getElementById(field); if (field === "magazzino") el = magazzinoSelect; else if (field === "settore") el = settoreSelect; else if (field === "categoria") el = categoriaSelect; else if (field === "marca") el = marcaSelect; if (el) f[field] = el.value; } return f; }',
    'async function aggiornaDatalist(campo, endpoint) { const filters = getCurrentFilters(); delete filters[campo]; const params = new URLSearchParams(); for (let [k,v] of Object.entries(filters)) if (v) params.append(k,v); const url = `${endpoint}?${params.toString()}`; try { const data = await apiFetch(url); const datalist = document.getElementById(`${campo}List`); if (datalist) { datalist.innerHTML = ""; data.forEach(item => { const opt = document.createElement("option"); opt.value = item[campo]; datalist.appendChild(opt); }); } } catch(err) { console.error(err); } }',
    'async function refreshAllDatalists() { for (let [campo, ep] of Object.entries(endpointMap)) await aggiornaDatalist(campo, ep); }',
    'let refreshDebounce; function refreshTabella() { caricaArticoli(); } function refreshTabellaDebounced() { clearTimeout(refreshDebounce); refreshDebounce = setTimeout(refreshTabella, 300); }',
    'function attachFormEvents() { const selects = [magazzinoSelect, settoreSelect, categoriaSelect, marcaSelect]; selects.forEach(s => s.addEventListener("change", () => { refreshAllDatalists(); refreshTabellaDebounced(); })); const inputs = ["descrizione", "lunghezza", "durezza", "codice_modello"]; inputs.forEach(id => { const el = document.getElementById(id); if (el) el.addEventListener("input", () => { refreshAllDatalists(); refreshTabellaDebounced(); }); }); }',
    'async function caricaArticoli() { try { const params = new URLSearchParams(); if (magazzinoSelect.value) params.append("magazzino", magazzinoSelect.value); if (settoreSelect.value) params.append("settore", settoreSelect.value); if (categoriaSelect.value) params.append("categoria", categoriaSelect.value); if (marcaSelect.value) params.append("marca", marcaSelect.value); if (descrizioneInput.value) params.append("descrizione", descrizioneInput.value); if (codiceModelloInput.value) params.append("codice_modello", codiceModelloInput.value); if (lunghezzaInput.value) params.append("lunghezza", lunghezzaInput.value); if (durezzaInput.value) params.append("durezza", durezzaInput.value); const res = await apiFetch(`/articoli?${params.toString()}`); if (res.success) { articoliCorrente = res.data; renderTabella(); } else showMessage(res.message, "error"); } catch(err) { showMessage(err.message, "error"); } }',
    'function compare(a,b,col) { let va = a[col], vb = b[col]; if (col === "quantita_totale" || col === "giacenza" || col === "quantita_obsoleta") { va = Number(va)||0; vb = Number(vb)||0; } else if (col === "lunghezza") { va = parseFloat(va)||0; vb = parseFloat(vb)||0; } else { va = (va||"").toString().toLowerCase(); vb = (vb||"").toString().toLowerCase(); } if (va < vb) return -1; if (va > vb) return 1; return 0; }',
