    'function getEditFilters() { const f = {}; for (let field of ["magazzino","settore","categoria","marca","descrizione","lunghezza","durezza","codice_modello"]) { let el = document.getElementById(`edit${field.charAt(0).toUpperCase()+field.slice(1)}`); if (!el) el = document.getElementById(`edit${field}`); if (el) f[field] = el.value; } return f; }',
    'async function aggiornaEditDatalist(campo, ep) { const filters = getEditFilters(); delete filters[campo]; const params = new URLSearchParams(); for (let [k,v] of Object.entries(filters)) if (v) params.append(k,v); const url = `${ep}?${params.toString()}`; try { const data = await apiFetch(url); const datalist = document.getElementById(`edit${campo.charAt(0).toUpperCase()+campo.slice(1)}List`); if (datalist) { datalist.innerHTML = ""; data.forEach(item => { const opt = document.createElement("option"); opt.value = item[campo]; datalist.appendChild(opt); }); } } catch(e) { console.error(e); } }',
